onClick:
{{
(() => {
  const questions = List_Questions.listData || [];
  const answers = appsmith.store.answers || {};
  const selectedDept = appsmith.store.selectedDepartment?.trim().toLowerCase();

  if (!questions.length) {
    showAlert("No questions found", "warning");
    return;
  }

  const invalid = questions.some(q => {
    const ans = answers[q.id];
    if (!ans || ans.YesNo === undefined) return false;
    if (Number(ans.YesNo) === 0) {
      const responsible = ans.ResponsiblePerson?.toString().trim();
      const action = ans.Action?.toString().trim();
      const due = ans.DueDate?.toString().trim();
      return (!responsible || !action || !due);
    }
    return false;
  });

  if (invalid) {
    showAlert("All 'No' answers must have Responsible Person, Action and Due Date", "error");
    return Promise.reject("Validation failed");
  }

  const versionId = "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === "x" ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });

  // 🔥 CHECK IF ALL DEPT QUESTIONS ARE NOW ANSWERED
  const deptQuestions = questions.filter(q =>
    q.Department?.trim().toLowerCase() === selectedDept
  );

  const allAnswered = deptQuestions.length > 0 && !deptQuestions.some(q => {
    const ans = answers[q.id];
    if (!ans || ans.YesNo === undefined) return true;
    if (Number(ans.YesNo) === 0) {
      const responsible = ans.ResponsiblePerson?.toString().trim();
      const action = ans.Action?.toString().trim();
      const due = ans.DueDate?.toString().trim();
      return (!responsible || !action || !due);
    }
    return false;
  });

  return storeValue("currentVersion", versionId)
    .then(() => InsertAnswers.run())
    .then(() => storeValue("originalAnswers", JSON.parse(JSON.stringify(answers))))
    .then(() => {
      // 🔥 ONLY SEND APPROVER EMAIL IF ALL QUESTIONS COMPLETE
      if (allAnswered) {
        return GetDepartmentApproverEmails.run()
          .then(() => {
            const hasApprovers = GetDepartmentApproverEmails.data?.length > 0;
            if (hasApprovers) {
              return SendApproverEmail.run();
            }
          });
      }
    })
    .then(() => {
      showAlert("Answers saved", "success");
    })
    .catch((err) => {
      if (err !== "Validation failed") {
        showAlert("Failed to save answers", "error");
      }
    });
})()
}}
